{
  "items": [
    {
      "term": "信息不对称",
      "contextual_explanations": [
        "【概念解构（破除陌生感）】：在此语境下，它并非泛指市场或社会中的知识差距，而是特指在提示工程中，用户与AI模型之间关于训练数据、内部逻辑和响应机制的认知鸿沟。",
        "【点石成金（回应好奇心）】：作者用这个词精准刻画了前文‘投其所好’原则的适用困境：用户试图‘讨好’AI，却因不了解其‘喜好’（如数据分布）而陷入盲目，导致沟通低效或失败。"
      ],
      "depth": [
        "【本质剥离】：不要停留在表面沟通障碍。其底层是AI作为黑箱系统的固有属性，源于模型训练过程的不可逆性和数据集的非透明性，这创造了用户无法完全掌控的认知壁垒。",
        "【第一性原理】：这触及了信息论中‘熵’的概念：系统内部状态（模型参数）的不可观测性导致外部（用户）信息缺失，从而引发决策不确定性，是热力学第二定律在智能交互中的体现。"
      ],
      "breadth": [
        "【跨界同构】：跳出AI领域，这与经济学中‘柠檬市场’（二手车市场）问题同构：买家因信息不足而无法准确评估商品质量，导致市场失灵，正如用户因不了解AI而无法优化提示。",
        "【高维演进/极端延伸】：在更宏大视野里，类似国家安全中的‘情报不对称’：一方掌握关键信息而另一方盲视，这驱动了从间谍活动到加密技术的整个博弈体系，映射到AI中则催生了可解释性研究和对抗性测试。"
      ]
    },
    {
      "term": "投其所好原则",
      "contextual_explanations": [
        "【概念解构（破除陌生感）】：在此语境下，它并非社交技巧的泛泛而谈，而是实体化为提示工程的核心策略：通过调整表达方式（如使用特定术语或结构）来匹配AI模型的训练数据偏好。",
        "【点石成金（回应好奇心）】：作者用这个词绝妙地连接了前文类比（如与文学爱好者谈《红楼梦》），因为它将人际沟通的直觉升华为可操作的AI交互方法论，强调了适应性而非强制命令。"
      ],
      "depth": [
        "【本质剥离】：不要停留在策略层面。其生效的底层逻辑是激活模型在训练数据中高频出现的模式，利用统计规律（如最大似然估计）来引导输出，本质是数据驱动而非逻辑推理。",
        "【第一性原理】：这触及了心理学中的‘共情机制’和机器学习中的‘归纳偏差’：系统（人或AI）基于过往经验（数据）形成响应偏好，有效沟通需逆向工程这些偏好以最小化认知负荷。"
      ],
      "breadth": [
        "【跨界同构】：跳出技术领域，这与市场营销中的‘客户画像’策略同构：企业通过数据分析了解消费者偏好来定制产品，正如用户通过提示调整来‘定制’AI响应。",
        "【高维演进/极端延伸】：在更宏大视野里，类似外交谈判中的‘文化适配’：使者需学习对方语言和习俗以达成协议，这映射到AI中则演变为多模态模型（如图像、文本融合）的跨域提示工程。"
      ]
    },
    {
      "term": "模型微调",
      "contextual_explanations": [
        "【概念解构（破除陌生感）】：在此语境下，它并非泛指机器学习中的参数调整，而是特指在提示工程框架下，用户通过迭代反馈（如修改提示词）来‘微调’AI的响应行为，而非改变底层模型。",
        "【点石成金（回应好奇心）】：作者用这个词精准呼应了前文‘追溯第一性原理’的探讨，因为它代表了用户从被动适应（投其所好）转向主动干预，试图在信息不对称中夺取部分控制权。"
      ],
      "depth": [
        "【本质剥离】：不要停留在技术操作。其底层是用户与AI之间的动态博弈：用户通过试错学习模型的行为边界，本质是利用反馈循环来近似反向传播，但受限于黑箱特性而只能局部优化。",
        "【第一性原理】：这触及了控制论中的‘闭环调节’原理：系统（AI）输出作为输入（提示）的反馈，用户通过调整输入来逼近目标输出，是熵减过程在交互层面的实现。"
      ],
      "breadth": [
        "【跨界同构】：跳出AI领域，这与生物进化中的‘自然选择’同构：环境（用户需求）通过选择压力（反馈）‘微调’物种（模型响应）的适应性，而非直接修改基因（模型参数）。",
        "【高维演进/极端延伸】：在更宏大视野里，类似组织管理中的‘敏捷迭代’：团队通过快速原型和用户反馈调整产品方向，这映射到AI中则催生了自动化提示优化工具和强化学习从人类反馈（RLHF）。"
      ]
    }
  ]
}

